const path = require('path');
const Module = require('module');

const dependencyRoot = path.resolve(__dirname, '../../../svelte-language-server/bin/node_modules');
const nodePath = process.env.NODE_PATH ? process.env.NODE_PATH.split(path.delimiter) : [];

if (!nodePath.includes(dependencyRoot)) {
  nodePath.unshift(dependencyRoot);
  process.env.NODE_PATH = nodePath.join(path.delimiter);
  Module._initPaths();
}

module.exports = require('./dist/src/index.js');
